/**
 * Split on object up based on the keys provided.
 * @param {Object} obj
 * @param {Array} keys
 * @returns
 */
export function splitObject(obj, keys) {
  const picked = {}
  const omitted = { ...obj }

  keys.forEach(key => {
    if (key in obj) {
      picked[key] = obj[key]
      delete omitted[key]
    }
  })

  return { picked, omitted, p: picked, o: omitted }
}
